// Worked focus: cmem-cleanup-attribute-portability — Use compiler cleanup attributes only behind a documented extension boundary with equivalent standard-C control flow.
/* Evidence: cmem-worked-cmem-resource-ownership-raii-patterns-2 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 1690; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct resources { int buffer; int stream; int lock; int release_trace; };

static int worked_cmem_resource_ownership_raii_patterns_2(struct resources *state) {
  if (state == NULL) return 0;
  if (state->lock) { state->release_trace = state->release_trace * 10 + 3; state->lock = 0; }
  if (state->stream) { state->release_trace = state->release_trace * 10 + 2; state->stream = 0; }
  if (state->buffer) { state->release_trace = state->release_trace * 10 + 1; state->buffer = 0; }
  return 1;
}

int main(void) {
  struct resources state = { 1, 1, 1, 0 };
  int first = worked_cmem_resource_ownership_raii_patterns_2(&state);
  int second = worked_cmem_resource_ownership_raii_patterns_2(&state);
  int invariant = first && second && state.release_trace == 321 && 6 > 0;
  printf("resources trace=%d invariant=%d\n", state.release_trace, invariant);
  return invariant ? 0 : 1;
}

